bad_hanuman = """        contentEn = "Shri Guru Charan Saroj Raj, Nij Manu Mukur Sudhari.\\nBarnaum Raghuvar Bimal Jasu, Jo Dayaku Phal Chari.\\nBudhi Heen Tanu Janike, Sumirow Pavan Kumar.\\nBal Buddhi Vidya Dehu Mohi, Harahu Kalesh Bikaar.\\n\\nJai Hanuman Gyan Gun Sagar. Jai Kapis Tihun Lok Ujagar.\\nRam Doot Atulit Bal Dhama. Anjani Putra Pavan Sut Nama.\\nMahabir Bikram Bajrangi. Kumati Nivar Sumati Ke Sangi.\\nKanchan Baran Viraj Subesa. Kanan Kundal Kunchit Kesa.\\n\\nHath Vajra Aur Dhvaja Viraje. Kandhe Moonj Janeu Saje.\\nSankar Suvan Kesri Nandan. Tej Pratap Maha Jag Vandan.\\nVidyavan Guni Ati Chatur. Ram Kaj Karibe Ko Atur.\\nPrabhu Charitra Sunibe Ko Rasiya. Ram Lakhan Sita Man Basiya.\\n\\n(This is a summarized short version of the complete Hanuman Chalisa reciting the glorious life and power of Lord Hanuman.)",
        contentHi = "श्रीगुरु चरन सरोज रज, निज मनु मुकुरु सुधारि।\\nबरनऊं रघुबर बिमल जसु, जो दायकु फल चारि॥\\nबुद्धिहीन तनु जानिके, सुमिरौं पवन-कुमार।\\nबल बुद्धि बिद्या देहु मोहिं, हरहु कलेस बिकार॥\\n\\nजय हनुमान ज्ञान गुन सागर। जय कपीस तिहुं लोक उजागर॥\\nरामदूत अतुलित बल धामा। अंजनि-पुत्र पवनसुत नामा॥\\nमहाबीर बिक्रम बजरंगी। कुमति निवार सुमति के संगी॥\\nकंचन बरन बिराज सुबेसा। कानन कुंडल कुंचित केसा॥\\n\\nहाथ बज्र औ ध्वजा बिराजै। कांधे मूंज जनेऊ साजै॥\\nसंकर सुवन केसरीनंदन। तेज प्रताप महा जग बंदन॥\\nबिद्यावान गुनी अति चातुर। राम काज करिबे को आतुर॥\\nप्रभु चरित्र सुनिबे को रसिया। राम लखन सीता मन बसिया॥\\n\\n(यह श्री हनुमान चालीसा का संक्षिप्त रूप है जो भगवान हनुमान की महिमा और शक्ति का वर्णन करता है।)","""

good_hanuman = """        contentEn = "Shri Guru Charan Saroj Raj, Nij Manu Mukur Sudhari.\\nBarnaum Raghuvar Bimal Jasu, Jo Dayaku Phal Chari.\\nBudhi Heen Tanu Janike, Sumirow Pavan Kumar.\\nBal Buddhi Vidya Dehu Mohi, Harahu Kalesh Bikaar.\\n\\nJai Hanuman Gyan Gun Sagar. Jai Kapis Tihun Lok Ujagar.\\nRam Doot Atulit Bal Dhama. Anjani Putra Pavan Sut Nama.\\nMahabir Bikram Bajrangi. Kumati Nivar Sumati Ke Sangi.\\nKanchan Baran Viraj Subesa. Kanan Kundal Kunchit Kesa.\\n\\nHath Vajra Aur Dhvaja Viraje. Kandhe Moonj Janeu Saje.\\nSankar Suvan Kesri Nandan. Tej Pratap Maha Jag Vandan.\\nVidyavan Guni Ati Chatur. Ram Kaj Karibe Ko Atur.\\nPrabhu Charitra Sunibe Ko Rasiya. Ram Lakhan Sita Man Basiya.\\n\\nSukshma Roop Dhari Siyahi Dikhava. Bikat Roop Dhari Lank Jarava.\\nBhima Roop Dhari Asur Sanghare. Ramachandra Ke Kaj Sanvare.\\nLaye Sanjivan Lakhan Jiyaye. Shri Raghuvir Harashi Ur Laye.\\nRaghupati Kinhi Bahut Badai. Tum Mam Priye Bharat-Hi Sam Bhai.\\n\\nSahas Badan Tumharo Yash Gaave. Us Kahi Shripati Kanth Lagaave.\\nSankadik Brahmadi Muneesa. Narad Sarad Sahit Aheesa.\\nYam Kuber Digpal Jahan Te. Kavi Kovid Kahi Sake Kahan Te.\\nTum Upkar Sugreevahin Keenha. Ram Milaye Rajpad Deenha.\\n\\nTumharo Mantra Vibheeshan Maana. Lankeshwar Bhay Sub Jag Jana.\\nYug Sahasra Yojan Par Bhanu. Leelyo Tahi Madhur Phal Janu.\\nPrabhu Mudrika Melikh Mukh Mahee. Jaladhi Langhi Gaye Achraj Nahee.\\nDurgam Kaj Jagat Ke Jete. Sugam Anugraha Tumhare Tete.\\n\\nRam Duware Tum Rakhavare. Hoat Na Agya Binu Paisare.\\nSub Sukh Lahai Tumhari Sarna. Tum Rakshak Kahu Ko Darna.\\nAapan Tej Samharo Aapai. Teenhon Lok Hank Te Kanpai.\\nBhoot Pisach Nikat Nahin Aavai. Mahavir Jab Naam Sunavai.\\n\\nNase Rog Harai Sab Peera. Japat Nirantar Hanumat Beera.\\nSankat Se Hanuman Chhudavai. Man Kram Vachan Dhyan Jo Lavai.\\nSub Par Ram Tapasvee Raja. Tin Ke Kaj Sakal Tum Saja.\\nAur Manorath Jo Koi Lavai. Sohi Amit Jeevan Phal Pavai.\\n\\nCharon Yug Partap Tumhara. Hai Parsiddh Jagat Ujiyara.\\nSadhu Sant Ke Tum Rakhware. Asur Nikandan Ram Dulhare.\\nAshta Siddhi Nav Nidhi Ke Daata. As Var Deen Janki Mata.\\nRam Rasayan Tumhare Pasa. Sada Raho Raghupati Ke Dasa.\\n\\nTumhare Bhajan Ram Ko Pavai. Janam Janam Ke Dukh Bisravai.\\nAnth Kaal Raghuvir Pur Jayee. Jahan Janam Hari-Bhakta Kahayee.\\nAur Devata Chitt Na Dharayi. Hanumat Sei Sarv Sukh Karayi.\\nSankat Kate Mite Sab Peera. Jo Sumirai Hanumat Balbeera.\\n\\nJai Jai Jai Hanuman Gosahin. Kripa Karahu Gurudev Ki Nyahin.\\nJo Sat Bar Path Kare Kohi. Chhutahi Bandi Maha Sukh Hohi.\\nJo Yah Padhe Hanuman Chalisa. Hoye Siddhi Sakhi Gaureesa.\\nTulsidas Sada Hari Chera. Keejai Das Hridaye Mein Dera.\\n\\nPavantanaye Sankat Haran, Mangal Moorti Roop.\\nRam Lakhan Sita Sahit, Hriday Basahu Sur Bhoop.",
        contentHi = "श्रीगुरु चरन सरोज रज, निज मनु मुकुरु सुधारि।\\nबरनऊं रघुबर बिमल जसु, जो दायकु फल चारि॥\\nबुद्धिहीन तनु जानिके, सुमिरौं पवन-कुमार।\\nबल बुद्धि बिद्या देहु मोहिं, हरहु कलेस बिकार॥\\n\\nजय हनुमान ज्ञान गुन सागर। जय कपीस तिहुं लोक उजागर॥\\nरामदूत अतुलित बल धामा। अंजनि-पुत्र पवनसुत नामा॥\\nमहाबीर बिक्रम बजरंगी। कुमति निवार सुमति के संगी॥\\nकंचन बरन बिराज सुबेसा। कानन कुंडल कुंचित केसा॥\\n\\nहाथ बज्र औ ध्वजा बिराजै। कांधे मूंज जनेऊ साजै॥\\nसंकर सुवन केसरीनंदन। तेज प्रताप महा जग बंदन॥\\nबिद्यावान गुनी अति चातुर। राम काज करिबे को आतुर॥\\nप्रभु चरित्र सुनिबे को रसिया। राम लखन सीता मन बसिया॥\\n\\nसूक्ष्म रूप धरि सियहिं दिखावा। बिकट रूप धरि लंक जरावा॥\\nभीम रूप धरि असुर संहारे। रामचंद्र के काज संवारे॥\\nलाय सजीवन लखन जियाये। श्रीरघुबीर हरषि उर लाये॥\\nरघुपति कीन्ही बहुत बड़ाई। तुम मम प्रिय भरतहि सम भाई॥\\n\\nसहस बदन तुम्हरो जस गावैं। अस कहि श्रीपति कंठ लगावैं॥\\nसनकादिक ब्रह्मादि मुनीसा। नारद सारद सहित अहीसा॥\\nजम कुबेर दिगपाल जहां ते। कबि कोबिद कहि सके कहां ते॥\\nतुम उपकार सुग्रीवहिं कीन्हा। राम मिलाय राज पद दीन्हा॥\\n\\nतुम्हरो मंत्र बिभीषन माना। लंकेस्वर भए सब जग जाना॥\\nजुग सहस्र जोजन पर भानू। लील्यो ताहि मधुर फल जानू॥\\nप्रभु मुद्रिका मेलि मुख माहीं। जलधि लांघि गये अचरज नाहीं॥\\nदुर्गम काज जगत के जेते। सुगम अनुग्रह तुम्हरे तेते॥\\n\\nराम दुआरे तुम रखवारे। होत न आज्ञा बिनु पैसारे॥\\nसब सुख लहै तुम्हारी सरना। तुम रक्षक काहू को डरना॥\\nआपन तेज सम्हारो आपै। तीनों लोक हांक तें कांपै॥\\nभूत पिसाच निकट नहिं आवै। महाबीर जब नाम सुनावै॥\\n\\nनासै रोग हरै सब पीरा। जपत निरंतर हनुमत बीरा॥\\nसंकट तें हनुमान छुड़ावै। मन क्रम बचन ध्यान जो लावै॥\\nसब पर राम तपस्वी राजा। तिन के काज सकल तुम साजा॥\\nऔर मनोरथ जो कोई लावै। सोइ अमित जीवन फल पावै॥\\n\\nचारों जुग परताप तुम्हारा। है परसिद्ध जगत उजियारा॥\\nसाधु संत के तुम रखवारे। असुर निकंदन राम दुलारे॥\\nअष्ट सिद्धि नौ निधि के दाता। अस बर दीन जानकी माता॥\\nराम रसायन तुम्हरे पासा। सदा रहो रघुपति के दासा॥\\n\\nतुम्हरे भजन राम को पावै। जनम जनम के दुख बिसरावै॥\\nअंतकाल रघुबर पुर जाई। जहां जन्म हरि-भक्त कहाई॥\\nऔर देवता चित्त न धरई। हनुमत सेइ सर्ब सुख करई॥\\nसंकट कटै मिटै सब पीरा। जो सुमिरै हनुमत बलबीरा॥\\n\\nजै जै जै हनुमान गोसाईं। कृपा करहु गुरुदेव की नाईं॥\\nजो सत बार पाठ कर कोई। छूटहि बंदि महा सुख होई॥\\nजो यह पढ़ै हनुमान चालीसा। होय सिद्धि साखी गौरीसा॥\\nतुलसीदास सदा हरि चेरा। कीजै नाथ हृदय मंह डेरा॥\\n\\nपवन तनय संकट हरन, मंगल मूरति रूप।\\nराम लखन सीता सहित, हृदय बसहु सुर भूप॥","""

